using MatPlotLibNet.Fidelity;
using MatPlotLibNet.Indicators;
using MatPlotLibNet.Models;
using MatPlotLibNet.Styling;

namespace MatPlotLibNet.Tests.Fidelity.Charts;

/// <summary>
/// Phase 6 — Financial indicator fidelity tests against pandas_ta reference PNGs.
///
/// The OHLC+volume dataset is generated by a closed-form formula that produces
/// byte-identical values in Python and C# (no RNG — Python PCG64 ≠ C# System.Random).
/// Formula: close = 100 + 5·sin(2πi/25) + 3·sin(2πi/7); high/low/open/volume derived.
/// </summary>
public class IndicatorFidelityTests : FidelityTest
{
    private const int N = 60;

    private static (double[] Open, double[] High, double[] Low, double[] Close, double[] Volume) Ohlc(int n = N)
    {
        var open   = new double[n];
        var high   = new double[n];
        var low    = new double[n];
        var close  = new double[n];
        var volume = new double[n];
        for (int i = 0; i < n; i++)
        {
            close[i]  = 100.0 + 5.0 * Math.Sin(2 * Math.PI * i / 25) + 3.0 * Math.Sin(2 * Math.PI * i / 7);
            high[i]   = close[i] + 1.0 + 0.5 * Math.Abs(Math.Sin(i * 0.5));
            low[i]    = close[i] - 1.0 - 0.5 * Math.Abs(Math.Cos(i * 0.5));
            open[i]   = close[i] + 0.3 * Math.Sin(i * 0.7);
            volume[i] = 2500.0 + 1500.0 * Math.Sin(i * 0.3);
        }
        return (open, high, low, close, volume);
    }

    private static double[] BarIndex(int n)
    {
        var x = new double[n];
        for (int i = 0; i < n; i++) x[i] = i;
        return x;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Overlay indicators (price + indicator on same axes)
    // ─────────────────────────────────────────────────────────────────────────

    [Theory]
    [InlineData("classic")]
    [InlineData("v2")]
    [Trait("Category", "Fidelity")]
    [FidelityTolerance(Rms = 60, Ssim = 0.55, DeltaE = 140)]   // 2 thin lines — pure #0000FF AA-diffuses below top-5 pixel threshold
    public void Sma_20_MatchesPandasTa(string themeId)
    {
        var (_, _, _, close, _) = Ohlc();
        var x = BarIndex(N);
        var figure = Plt.Create()
            .WithSize(FigWidth, FigHeight)
            .WithTheme(ResolveTheme(themeId))
            .AddSubPlot(1, 1, 1, ax => ax
                .WithTitle("SMA(20) overlay")
                .Plot(x, close, s => s.Label = "close")
                .Sma(20, i => i.Label = "SMA(20)")
                .SetXLabel("bar")
                .SetYLabel("price")
                .WithLegend())
            .Build();
        AssertFidelity(figure, "ind_sma");
    }

